def merge_configs(default, override):
    result = {}
    # Helper to copy without mutating inputs
    def copy_value(v):
        if isinstance(v, dict):
            return merge_configs({}, v)
        elif isinstance(v, list):
            return v[:]  # shallow copy
        else:
            return v

    # Start with all keys from default
    for key, default_val in default.items():
        if key in override:
            override_val = override[key]
            if isinstance(default_val, dict) and isinstance(override_val, dict):
                result[key] = merge_configs(default_val, override_val)
            else:
                result[key] = copy_value(override_val)
        else:
            result[key] = copy_value(default_val)

    # Add keys that exist only in override
    for key in override:
        if key not in default:
            result[key] = copy_value(override[key])

    return result
