def parse_log_lines(lines):
    from collections import defaultdict
    result = defaultdict(list)
    for line in lines:
        stripped = line.strip()
        if not stripped:
            continue
        level = None
        if stripped[0] == '[':
            end = stripped.find(']')
            if end != -1:
                level = stripped[1:end].strip().upper()
        elif ':' in stripped:
            # extract word before first colon
            prefix = stripped.split(':', 1)[0].strip()
            if prefix:
                level = prefix.upper()
        if level:
            result[level].append(line)
    return dict(result)
```

